#!/usr/bin/env bash
# ============================================================
# seed-catalog.sh -- Seed the race_catalog table via Supabase REST API
#
# Usage:  ./seed-catalog.sh <SERVICE_ROLE_KEY>
#
# Requires: curl, a valid Supabase service_role key
# The anon key does NOT have write access (RLS blocks it).
# ============================================================
set -euo pipefail

if [ $# -lt 1 ]; then
  echo "Usage: $0 <SERVICE_ROLE_KEY>"
  echo ""
  echo "Get your service_role key from:"
  echo "  Supabase Dashboard > Project Settings > API > service_role (secret)"
  exit 1
fi

SERVICE_ROLE_KEY="$1"
SUPABASE_URL="https://tpnfkumkvxnrurjuaxdq.supabase.co"
ENDPOINT="${SUPABASE_URL}/rest/v1/race_catalog"

BATCH=0
TOTAL=0
ERRORS=0

post_batch() {
  local json="$1"
  local count="$2"
  BATCH=$((BATCH + 1))
  
  HTTP_CODE=$(curl -s -o /tmp/seed-response.txt -w "%{http_code}" \
    -X POST "${ENDPOINT}" \
    -H "apikey: ${SERVICE_ROLE_KEY}" \
    -H "Authorization: Bearer ${SERVICE_ROLE_KEY}" \
    -H "Content-Type: application/json" \
    -H "Prefer: resolution=merge-duplicates" \
    -d "${json}")
  
  if [ "$HTTP_CODE" -ge 200 ] && [ "$HTTP_CODE" -lt 300 ]; then
    TOTAL=$((TOTAL + count))
    echo "  Batch ${BATCH}: ${count} records -> HTTP ${HTTP_CODE} OK"
  else
    ERRORS=$((ERRORS + 1))
    echo "  Batch ${BATCH}: ${count} records -> HTTP ${HTTP_CODE} FAILED"
    cat /tmp/seed-response.txt
    echo ""
  fi
}

echo "Seeding race_catalog via Supabase REST API..."
echo ""

